namespace sv_42da82e6865a4a7ab7900ae142ee425a;

/// <summary>
/// Holds all wizard form data. Registered as scoped so each circuit
/// (each user connection) gets its own independent instance.
/// </summary>
public class WizardState
{
    // Step 1 – Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2 – Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    public bool IsStepCompleted(int step) => step switch
    {
        1 => !string.IsNullOrWhiteSpace(Name) && !string.IsNullOrWhiteSpace(Email),
        2 => JobHistory.Count > 0,
        3 => References.Count > 0,
        _ => false
    };
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

namespace sv_42da82e6865a4a7ab7900ae142ee425a;

/// <summary>
/// Lightweight record cascaded via CascadingValueSource so the static
/// layout can read the current step. Crosses render mode boundaries.
/// </summary>
public record WizardProgress(int CurrentStep, bool[] CompletedSteps)
{
    public static WizardProgress Default => new(0, [false, false, false]);
}

