@inherits LayoutComponentBase

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (Progress is { CurrentStep: > 0 })
            {
                <nav class="d-flex align-items-center gap-3 flex-grow-1">
                    <span class="fw-semibold">Step @Progress.CurrentStep of 4</span>
                    @for (int i = 0; i < _steps.Length; i++)
                    {
                        var step = i + 1;
                        var isCurrent = step == Progress.CurrentStep;
                        var isCompleted = i < Progress.CompletedSteps.Length && Progress.CompletedSteps[i];
                        var css = isCurrent ? "btn btn-primary btn-sm"
                                : isCompleted ? "btn btn-success btn-sm"
                                : "btn btn-outline-secondary btn-sm";

                        <a href="@_steps[i].Href" class="@css">
                            @if (isCompleted && !isCurrent) { <span>✓ </span> }
                            @_steps[i].Label
                        </a>
                    }
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

