@page "/apply/personal-info"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h3>Step 1: Personal Information</h3>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email</label>
    <input class="form-control" type="email" @bind="Wizard.Email" />
</div>

<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(1, [
            Wizard.IsStepCompleted(1),
            Wizard.IsStepCompleted(2),
            Wizard.IsStepCompleted(3),
        ]));
    }

    private async Task Next()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(2, [
            Wizard.IsStepCompleted(1),
            Wizard.IsStepCompleted(2),
            Wizard.IsStepCompleted(3),
        ]));
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Experience</PageTitle>

<h3>Step 2: Work Experience</h3>

@foreach (var job in Wizard.JobHistory)
{
    <div class="card mb-2 p-2">
        <strong>@job.Title</strong> at @job.Company (@job.Years)
    </div>
}

<div class="border rounded p-3 mb-3">
    <h5>Add a position</h5>
    <div class="mb-2">
        <label class="form-label">Company</label>
        <input class="form-control" @bind="_company" />
    </div>
    <div class="mb-2">
        <label class="form-label">Job Title</label>
        <input class="form-control" @bind="_title" />
    </div>
    <div class="mb-2">
        <label class="form-label">Years</label>
        <input class="form-control" @bind="_years" />
    </div>
    <button class="btn btn-outline-primary btn-sm" @onclick="AddJob">+ Add</button>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("/apply/personal-info")'>← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string _company = "", _title = "", _years = "";

    protected override async Task OnInitializedAsync()
    {
        await NotifyProgress(2);
    }

    private void AddJob()
    {
        if (string.IsNullOrWhiteSpace(_company)) return;
        Wizard.JobHistory.Add(new JobEntry { Company = _company, Title = _title, Years = _years });
        _company = _title = _years = "";
    }

    private async Task Next()
    {
        await NotifyProgress(3);
        Nav.NavigateTo("/apply/references");
    }

    private async Task NotifyProgress(int step) =>
        await ProgressSource.NotifyChangedAsync(new WizardProgress(step, [
            Wizard.IsStepCompleted(1),
            Wizard.IsStepCompleted(2),
            Wizard.IsStepCompleted(3),
        ]));
}

@page "/apply/references"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – References</PageTitle>

<h3>Step 3: References</h3>

@foreach (var r in Wizard.References)
{
    <div class="card mb-2 p-2">
        <strong>@r.Name</strong> — @r.Email (@r.Relationship)
    </div>
}

<div class="border rounded p-3 mb-3">
    <h5>Add a reference</h5>
    <div class="mb-2">
        <label class="form-label">Name</label>
        <input class="form-control" @bind="_name" />
    </div>
    <div class="mb-2">
        <label class="form-label">Email</label>
        <input class="form-control" type="email" @bind="_email" />
    </div>
    <div class="mb-2">
        <label class="form-label">Relationship</label>
        <input class="form-control" @bind="_relationship" />
    </div>
    <button class="btn btn-outline-primary btn-sm" @onclick="AddReference">+ Add</button>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("/apply/experience")'>← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string _name = "", _email = "", _relationship = "";

    protected override async Task OnInitializedAsync()
    {
        await NotifyProgress(3);
    }

    private void AddReference()
    {
        if (string.IsNullOrWhiteSpace(_name)) return;
        Wizard.References.Add(new ReferenceContact { Name = _name, Email = _email, Relationship = _relationship });
        _name = _email = _relationship = "";
    }

    private async Task Next()
    {
        await NotifyProgress(4);
        Nav.NavigateTo("/apply/review");
    }

    private async Task NotifyProgress(int step) =>
        await ProgressSource.NotifyChangedAsync(new WizardProgress(step, [
            Wizard.IsStepCompleted(1),
            Wizard.IsStepCompleted(2),
            Wizard.IsStepCompleted(3),
        ]));
}

@page "/apply/review"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Review</PageTitle>

<h3>Step 4: Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <p><strong>Name:</strong> @Wizard.Name</p>
    <p><strong>Email:</strong> @Wizard.Email</p>
    @if (!Wizard.IsStepCompleted(1))
    {
        <span class="text-danger">⚠ Incomplete — <a href="/apply/personal-info">fill in</a></span>
    }
</div>

<div class="card mb-3 p-3">
    <h5>Work Experience</h5>
    @if (Wizard.JobHistory.Count == 0)
    {
        <span class="text-danger">⚠ No entries — <a href="/apply/experience">add experience</a></span>
    }
    else
    {
        <ul>
            @foreach (var job in Wizard.JobHistory)
            {
                <li>@job.Title at @job.Company (@job.Years)</li>
            }
        </ul>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (Wizard.References.Count == 0)
    {
        <span class="text-danger">⚠ No references — <a href="/apply/references">add references</a></span>
    }
    else
    {
        <ul>
            @foreach (var r in Wizard.References)
            {
                <li>@r.Name — @r.Email (@r.Relationship)</li>
            }
        </ul>
    }
</div>

<div class="d-flex gap-2">
    <button class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("/apply/references")'>← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(4, [
            Wizard.IsStepCompleted(1),
            Wizard.IsStepCompleted(2),
            Wizard.IsStepCompleted(3),
        ]));
    }

    private void Submit()
    {
        // TODO: persist application to a database
    }
}

